exercises.solution_code:
#include <iostream>
#include <string>

class Vehicle
{
public:
    std::string brand{};
    int year{};

    void printInfo() const
    {
        std::cout << "Vehicle: " << brand << " (" << year << ")" << '\n';
    }
};

class Car : public Vehicle
{
public:
    int doors{};

    void printCarInfo() const
    {
        std::cout << "Car: " << brand << " (" << year << "), " << doors << " doors" << '\n';
    }
};

int main()
{
    std::string brand{};
    int year{};
    int doors{};
    std::cin >> brand >> year >> doors;

    Car car{};
    car.brand = brand;
    car.year = year;
    car.doors = doors;

    car.printInfo();
    car.printCarInfo();

    return 0;
}

