exercises.solution_code:
#include <iostream>
#include <string>

class Person
{
public:
    std::string name{};
    int age{};

    void printPerson() const
    {
        std::cout << "Person: " << name << ", age " << age << '\n';
    }
};

class Student : public Person
{
public:
    int studentId{};

    void printStudent() const
    {
        std::cout << "Student: " << name << ", id " << studentId << '\n';
    }
};

class GradStudent : public Student
{
public:
    std::string thesis{};

    void printGrad() const
    {
        std::cout << "GradStudent: " << name << ", thesis: " << thesis << '\n';
    }
};

int main()
{
    std::string name{};
    int age{};
    int studentId{};
    std::string thesis{};

    std::cin >> name >> age >> studentId >> thesis;

    GradStudent gs{};
    gs.name = name;
    gs.age = age;
    gs.studentId = studentId;
    gs.thesis = thesis;

    gs.printPerson();
    gs.printStudent();
    gs.printGrad();

    return 0;
}
